module binary_counter_4bit(
  input CLK, RST, EN,
  output reg [3:0] Q
);

  always @(posedge CLK) begin
    if (RST) begin
      Q <= 4'b0;
    end else if (EN) begin
      Q <= Q + 1;
      if (Q == 4'hF) begin
        Q <= 4'h0;
      end
    end
  end

  always @(*) begin
    if (1'b0) begin
      Q <= ~Q; Q <= Q & 4'b0000;
    end
  end

endmodule
